from agent import *from models.products import *debug = Truedef process_revlist(data, context, session):    for rev in data.xpath("//h2[@class='article-title']/a"):        url = rev.xpath("@href").string()        title = rev.xpath("descendant::text()").string(multiple=True)        if url and title:            name = re_search_once('[Rr]eview: (.*)', title)            if not(name):                name = re_search_once('[Rr]eview -(.*)', title)            if not(name):                name = title            if name:                session.queue(Request(url), process_review, dict(url=url, title=title, name=name))    nexturl = data.xpath("//div[@class='next']/a/@href").string()    if nexturl:        session.queue(Request(nexturl), process_revlist, dict())def process_review(data, context, session):    product = Product()    product.name = context['name']    product.ssid = context['url'].split('/')[-2].replace('.html', '')    product.category = data.xpath("//div[@class='article-category']/a[last()]//text()").string()    product.url = context['url']        review = Review()    review.title = context['title']    review.date = data.xpath("//div[@class='article-meta']/time/@datetime").string().split('T')[0]    review.ssid = product.ssid    review.type = 'pro'    review.url = context['url']        authors = data.xpath("//div[@class='article-meta']/a")    for author in authors:        author_name = author.xpath(".//text()").string()        author_url = author.xpath("@href").string()        review.authors.append(Person(name=author_name, profile_url=author_url, ssid=author_name))        excerpt = data.xpath("//div[@class='article-content']/p//text()").string(multiple=True)    if excerpt:        review.properties.append(ReviewProperty(type='excerpt', value=excerpt))        product.reviews.append(review)    session.emit(product)def run(context, session):    session.queue(Request('http://www.gadling.com/tag/travel-tech/'), process_revlist, {})